            CALL spa_dberror('T16:ทะเบียน '||NEW.membership_no||' เลขบัญชีไม่เท่ากับ 10 หลัก');
        end if;

        if IS_NUMBER(NEW.bank_acc_no)= 0 then
            CALL spa_dberror('T20:ทะเบียน '||NEW.membership_no||' เลขบัญชีรูปแบบไม่ถูกต้อง');
        end if;
    end if;
RETURN NEW;
end
